// ORCHESTRATION archetype: resume from last incomplete step
const requiredSteps = await this.freedom.getArray(tenantId, 'onboardingSteps');
const completedSteps = existing?.completedSteps ?? [];
for (const step of requiredSteps) {
  if (completedSteps.includes(step)) continue;  // already done
  const result = await this.executeStep(step, tenantId, userId);
  if (!result.isSuccess) return result;
  // DNA-8: persist BEFORE advancing
  await this.db.storeDocument(tenantId, 'progress', { step, completedAt }, userId);
  completedSteps.push(step);
}
// Gate: emit completion ONLY when all steps done
if (completedSteps.length < requiredSteps.length) return DataProcessResult.failure('INCOMPLETE');
